record_types.code:
type libmosquitto_tls is record
   cafile      :
     Interfaces
       .C
       .Strings
       .chars_ptr;
   capath      :
     Interfaces
       .C
       .Strings
       .chars_ptr;
   certfile    :
     Interfaces
       .C
       .Strings
       .chars_ptr;
   keyfile     :
     Interfaces
       .C
       .Strings
       .chars_ptr;
   ciphers     :
     Interfaces
       .C
       .Strings
       .chars_ptr;
   tls_version :
     Interfaces
       .C
       .Strings
       .chars_ptr;
   pw_callback :
     access function
       (arg1 : Interfaces.C.Strings.chars_ptr;
        arg2 : int;
        arg3 : int;
        arg4 : System.Address)
        return int;
   cert_reqs   : aliased int;
end record;

type libmosquitto_will is record
   topic      :
     Interfaces
       .C
       .Strings
       .chars_ptr;
   payload    : System.Address;
   payloadlen : aliased int;
   qos        : aliased int;
   retain     :
     aliased Extensions.bool;
end record;

type mosquitto_message is record
   mid        : aliased int;
   topic      :
     Interfaces
       .C
       .Strings
       .chars_ptr;
   payload    : System.Address;
   payloadlen : aliased int;
   qos        : aliased int;
   retain     :
     aliased Extensions.bool;
end record;

